To parse formulas that reference other formulas, you'll need to implement a recursive approach. Here's an example of how you could do this in Python:

```python
class Formula:
    def __init__(self, name, formula):
        self.name = name
        self.formula = formula

    @classmethod
    def lookup(cls, name):
        # Replace this with your actual formula lookup logic
        return cls(name, f"Formula {name}")

    def __str__(self):
        return self.formula

    def __repr__(self):
        return f"Formula({self.name}, {self.formula})"

    def parse(self):
        # Replace this with your actual formula parsing logic
        return self.formula

    def resolve_references(self):
        formula = self.parse()
        # Use regular expressions to find references to other formulas
        import re
        references = re.findall(r'\b\w+\b', formula)
        for reference in references:
            # If the reference is a valid formula name, replace it with its value
            formula = formula.replace(reference, str(Formula.lookup(reference).resolve_references()))
        return formula

